    processId: waitingProcessSummary.processId,
    processDisplayLabel: waitingProcessSummary.displayLabel,
    updatedAt:
      readyProcessMaterialsFixture.currentArtifacts[0]?.updatedAt ??
      waitingProcessSummary.updatedAt,
